def _check_xml_security(file_path: str) -> List[str]:
    """
    Check for potential XML security issues like XXE attacks, 
    billion laughs attack, etc.
    """
    errors = []
    try:
        with open(file_path, 'r', encoding='utf-8', errors='ignore') as f:
            content = f.read(50000)  # Read first 50KB for checks

        # Check for entity declarations that could indicate XXE
        dangerous_patterns = [
            ('<!ENTITY', 'External/internal entity declaration detected (potential XXE attack).'),
            ('SYSTEM "file:', 'SYSTEM file reference detected (potential XXE attack).'),
            ('SYSTEM "http:', 'SYSTEM HTTP reference detected (potential SSRF).'),
            ('SYSTEM "https:', 'SYSTEM HTTPS reference detected (potential SSRF).'),
            ('SYSTEM "ftp:', 'SYSTEM FTP reference detected (potential SSRF).'),
        ]

        content_upper = content.upper()
        for pattern, message in dangerous_patterns:
            if pattern.upper() in content_upper:
                errors.append(f"Security warning: {message}")

    except UnicodeDecodeError:
        pass  # Binary-like content; will fail XML parsing later
    except Exception as e:
        errors.append(f"Error during security check: {str(e)}")

    return errors


def _extract_namespaces(root: etree._Element) -> Dict[str, str]:
    """Extract all namespaces used in the XML document."""
    namespaces = {}
    for elem in root.iter():
        if hasattr(elem, 'nsmap'):
            for prefix, uri in elem.nsmap.items():
                if prefix is not None:
                    namespaces[prefix] = uri
                else:
                    namespaces['default'] = uri
    return namespaces


def _count_elements(root: etree._Element) -> int:
    """Count total number of elements in the XML tree."""
    count = 0
    for _ in root.iter():
        count += 1
    return count


def _validate_against_xsd(
    tree: etree._ElementTree,
    xsd_schema_path: str
) -> List[str]:
    """Validate the XML tree against an XSD schema."""
    errors = []

    if not os.path.exists(xsd_schema_path):
        errors.append(f"XSD schema file not found: {xsd_schema_path}")
        return errors

    try:
        with open(xsd_schema_path, 'r') as schema_file:
            schema_doc = etree.parse(schema_file)
            schema = etree.XMLSchema(schema_doc)
    except etree.XMLSchemaParseError as e:
        errors.append(f"Invalid XSD schema: {str(e)}")
        return errors
    except Exception as e:
        errors.append(f"Error loading XSD schema: {str(e)}")
        return errors

    try:
        schema.assertValid(tree)
    except etree.DocumentInvalid as e:
        errors.append(f"XML does not conform to schema: {str(e)}")
        # Collect all validation errors
        for error in schema.error_log:
            errors.append(
                f"Schema validation error (line {error.line}): {error.message}"
            )

    return errors


def _check_structure(root: etree._Element) -> List[str]:
    """Perform additional structural checks on the XML."""
    warnings = []

    # Check for empty root element
    if len(root) == 0 and (root.text is None or root.text.strip() == ''):
        warnings.append("Root element is empty (no children or text content).")

    # Check for deeply nested structures (potential issue)
    max_depth = _get_max_depth(root)
    if max_depth > 50:
        warnings.append(
            f"XML has very deep nesting (depth: {max_depth}). "
            "This might indicate a problem."
        )

    # Check for duplicate IDs if 'id' attributes are used
    ids = []
    duplicate_ids = []
    for elem in root.iter():
        elem_id = elem.get('id') or elem.get('Id') or elem.get('ID')
        if elem_id:
            if elem_id in ids:
                duplicate_ids.append(elem_id)
            else:
                ids.append(elem_id)

    if duplicate_ids:
        warnings.append(
            f"Duplicate id attributes found: {', '.join(set(duplicate_ids))}"
        )

    return warnings


def _get_max_depth(element: etree._Element, current_depth: int = 1) -> int:
    """Recursively find the maximum depth of the XML tree."""
    if len(element) == 0:
        return current_depth
    return max(
        _get_max_depth(child, current_depth + 1) for child in element
    )


def format_validation_report(result: Dict[str, Any]) -> str:
    """Format the validation result into a human-readable report."""
    lines = []
    lines.append("=" * 60)
    lines.append("XML VALIDATION REPORT")
    lines.append("=" * 60)

    status = "✅ VALID" if result['valid'] else "❌ INVALID"
    lines.append(f"Status: {status}")
    lines.append("")

    if result['root_tag']:
        lines.append(f"Root Element: {result['root_tag']}")
        lines.append(f"Total Elements: {result['element_count']}")

    if result['namespaces']:
        lines.append("\nNamespaces:")
        for prefix, uri in result['namespaces'].items():
            lines.append(f"  {prefix}: {uri}")

    if result['errors']:
        lines.append(f"\nErrors ({len(result['errors'])}):")
        for i, error in enumerate(result['errors'], 1):
            lines.append(f"  {i}. {error}")

    if result['warnings']:
        lines.append(f"\nWarnings ({len(result['warnings'])}):")
        for i, warning in enumerate(result['warnings'], 1):
            lines.append(f"  {i}. {warning}")

    lines.append("=" * 60)
    return "\n".join(lines)


